**.hsplus for the LOGIC:**
```hsplus
// inventory-system.hsplus - How inventory works
import { items } from "./items.holo";
import { clamp } from "@holoscript/std";

interface InventorySlot {
  item: Item | null;
  quantity: number;
}

export system InventoryManager {
  private slots: InventorySlot[] = [];
  private maxSlots: number = 30;
  private weight: number = 0;
  private maxWeight: number = 100;

  addItem(itemId: string, quantity: number = 1): boolean {
    const item = items.get(itemId);
    if (!item) return false;

    // Weight check
    const newWeight = this.weight + (item.weight * quantity);
    if (newWeight > this.maxWeight) {
      UI.toast("Too heavy!");
      return false;
    }

    // Stackable items
    if (item.stackable) {
      const existing = this.slots.find(s => s.item?.id === itemId);
      if (existing) {
        existing.quantity = Math.min(
          existing.quantity + quantity,
          item.max_stack
        );
        this.weight = newWeight;
        return true;
      }
    }

    // Find empty slot
    const empty = this.slots.findIndex(s => s.item === null);
    if (empty === -1) {
      UI.toast("Inventory full!");
      return false;
    }

    this.slots[empty] = { item, quantity };
    this.weight = newWeight;
    return true;
  }

  useItem(slotIndex: number): void {
    const slot = this.slots[slotIndex];
    if (!slot?.item) return;

    // Complex use logic
    switch (slot.item.effect) {
      case "heal":
        Player.health = clamp(Player.health + slot.item.value, 0, Player.maxHealth);
        break;
      case "mana":
        Player.mana = clamp(Player.mana + slot.item.value, 0, Player.maxMana);
        break;
      // ... more cases
    }

    slot.quantity--;
    if (slot.quantity <= 0) {
      this.slots[slotIndex] = { item: null, quantity: 0 };
    }
  }
}
```

**The pattern:**
```
.holo = Item definitions (WHAT exists)
.hsplus = Inventory logic (HOW it works)
```

If it's just listing items → .holo
If it's managing state, calculations, UI → .hsplus

Great question! Error handling is fundamentally different.

**.holo - Declarative validation:**
```holo
// Errors are structural - the parser catches them
composition "ValidScene" {

  // Type constraints
  object "Player" {
    position: [0, 0, 0]  // Must be [x, y, z]
    health: 100          // Must be number
    name: "Hero"         // Must be string
  }

  // Required connections
  logic {
    // If "Door" doesn't exist, parser error
    on_interact("Door") {
      Door.open()
    }
  }
}

// .holo errors happen at:
// 1. Parse time - syntax errors
// 2. Validation time - missing references
// 3. Load time - asset not found
```

**.hsplus - Runtime error handling:**
```hsplus
// Full try/catch, error propagation, custom errors
import { Result, Ok, Err } from "@holoscript/std";

export system GameLoader {

  async loadWorld(path: string): Promise<Result<World, LoadError>> {
    try {
      // File operations can fail
      const file = await fs.read(path);
      if (!file) {
        return Err(new LoadError("FILE_NOT_FOUND", path));
      }

      // Parsing can fail
      const parsed = parse(file);
      if (!parsed.valid) {
        return Err(new LoadError("PARSE_ERROR", parsed.errors));
      }

      // Asset loading can fail
      const assets = await this.loadAssets(parsed.required_assets);
      if (assets.missing.length > 0) {
        console.warn(`Missing assets: ${assets.missing.join(", ")}`);
        // Graceful degradation
        assets.missing.forEach(a => this.useDefaultAsset(a));
      }

      return Ok(new World(parsed, assets));

    } catch (e) {
      // Catch unexpected errors
      console.error("Unexpected error loading world", e);
      return Err(new LoadError("UNKNOWN", e.message));
    }
  }

  private handleError(error: LoadError): void {
    switch (error.code) {
      case "FILE_NOT_FOUND":
        UI.showError("World file not found");
        break;
      case "PARSE_ERROR":
        UI.showError("Corrupted world file");
        // Offer to load backup
        UI.prompt("Load last backup?", () => this.loadBackup());
        break;
      default:
        UI.showError("Failed to load world");
    }
  }
}

// Custom error types
class LoadError extends Error {
  constructor(
    public code: string,
    public details: unknown
  ) {
    super(`Load failed: ${code}`);
  }
}
```

**Comparison:**
```
.holo errors:                    .hsplus errors:
─────────────                    ─────────────────
✓ Caught at compile/load         ✓ Caught at runtime
✓ Usually clear messages         ✓ Custom error types  
✓ Fix before running             ✓ try/catch/finally
✗ No runtime handling            ✓ Graceful degradation
✗ All-or-nothing                 ✓ Partial recovery
```

**Best practice:**

```hsplus
// Wrap .holo loading in .hsplus error handling
async function safeLoadScene(holoPath: string): World | null {
  try {
    return await loadWorld(holoPath);
  } catch (e) {
    if (e instanceof HoloParseError) {
      console.error(`Invalid .holo file: ${e.line}:${e.column}`);
      console.error(e.message);
    }
    return null;
  }
}
```

**Rule:** .holo is fail-fast (good!). .hsplus handles the failures gracefully.

