```hsplus
// level-manager.hsplus - Pure logic, no data
import { loadWorld } from "@holoscript/core";

export class LevelManager {
  private currentLevel: World | null = null;

  async loadLevel(id: string): Promise<void> {
    // Clean - loads .holo file dynamically
    const levelPath = `./levels/${id}.holo`;
    this.currentLevel = await loadWorld(levelPath);

    // Logic only
    this.spawnEnemies();
    this.placeCollectibles();
    this.activateExitPortal();
  }

  private spawnEnemies(): void {
    const groups = this.currentLevel.query("enemy_group");
    for (const group of groups) {
      for (let i = 0; i < group.count; i++) {
        const pos = this.randomInArea(group.patrol_area);
        const enemy = Enemy.spawn(group.type, pos, group.level);
        if (group.behavior === "pack") {
          enemy.setPackLeader(groups[0].entities[0]);
        }
      }
    }
  }

  private placeCollectibles(): void {
    // Logic that's too complex for .holo
    const collectibles = this.currentLevel.query("collectibles");
    collectibles.coins.forEach((pos, i) => {
      // Add slight random offset
      const offset = [Math.random() * 2 - 1, 0, Math.random() * 2 - 1];
      Collectible.spawn("coin", vecAdd(pos, offset));
    });
  }
}
```

**Refactoring steps:**

```
1. Identify data vs logic
   ├── Data (positions, counts, names) → .holo
   └── Logic (calculations, conditionals) → .hsplus

2. Extract data to .holo files
   └── One .holo per level/scene/config

3. Load .holo dynamically in .hsplus
   └── await loadWorld("path/to/file.holo")

4. Keep behavior in .hsplus
   └── The "how it works" stays as code
```

**Benefits:**
- AI agents can edit levels without touching code
- Designers can modify .holo without coding knowledge
- Clear separation of concerns
- Smaller, focused files
- Version control shows content vs logic changes separately

