      inventory.addItem("health_potion", 3);

      expect(inventory.getItemCount("health_potion")).toBe(8);
      expect(inventory.getUsedSlots()).toBe(1);
    });

    it("respects max stack limit", () => {
      inventory.addItem("health_potion", 15);
      inventory.addItem("health_potion", 10);

      // Max stack is 20
      expect(inventory.getItemCount("health_potion")).toBe(20);
    });

    it("rejects when overweight", () => {
      // Heavy item weighs 30
      inventory.addItem("iron_ingot", 1); // weight: 10
      inventory.addItem("iron_ingot", 1); // weight: 20

      const result = inventory.addItem("iron_ingot", 4); // would be 60 > 50

      expect(result).toBe(false);
      expect(inventory.getTotalWeight()).toBe(20);
    });

    it("rejects when inventory full", () => {
      // Fill all 10 slots with non-stackable items
      for (let i = 0; i < 10; i++) {
        inventory.addItem(`unique_item_${i}`, 1);
      }

      const result = inventory.addItem("another_item", 1);

      expect(result).toBe(false);
    });
  });

  describe("useItem", () => {
    it("applies heal effect", () => {
      const mockPlayer = mock({ health: 50, maxHealth: 100 });
      inventory.setPlayer(mockPlayer);
      inventory.addItem("health_potion", 1);

      inventory.useItem(0);

      expect(mockPlayer.health).toBe(100); // heals 50
    });

    it("removes item after use", () => {
      inventory.addItem("health_potion", 1);

      inventory.useItem(0);

      expect(inventory.getItemCount("health_potion")).toBe(0);
    });

    it("decrements stack count", () => {
      inventory.addItem("health_potion", 5);

      inventory.useItem(0);

      expect(inventory.getItemCount("health_potion")).toBe(4);
    });
  });
});
