.hsplus IS essentially TypeScript with HoloScript extensions! They interoperate seamlessly.

**The relationship:**
```
TypeScript ⊂ .hsplus

.hsplus = TypeScript + HoloScript features
```

**Standard TypeScript in .hsplus:**
```hsplus
// utils.hsplus - Pure TypeScript works fine!
import { vec3 } from "@holoscript/std";

// Regular TypeScript interfaces
interface Player {
  id: string;
  name: string;
  position: vec3;
  stats: PlayerStats;
}

interface PlayerStats {
  health: number;
  mana: number;
  level: number;
}

// Regular TypeScript functions
function calculateDamage(attacker: Player, defender: Player, base: number): number {
  const attackPower = attacker.stats.level * 2 + 10;
  const defense = defender.stats.level + 5;
  return Math.max(1, Math.floor(base * attackPower / defense));
}

// Regular TypeScript classes
class GameEvent<T> {
  private listeners: ((data: T) => void)[] = [];

  on(callback: (data: T) => void): void {
    this.listeners.push(callback);
  }

  emit(data: T): void {
    this.listeners.forEach(l => l(data));
  }
}

// Export for use anywhere
export { Player, PlayerStats, calculateDamage, GameEvent };
```

**HoloScript extensions to TypeScript:**
```hsplus
// game-systems.hsplus - HoloScript adds these features

// 1. `system` keyword - ECS pattern
export system MovementSystem {
  // System-specific state
  private speed: number = 5;

  // Runs every frame
  update(dt: number) {
    for (const entity of this.query("moveable")) {
      entity.position = vec3Add(
        entity.position,
        vec3Scale(entity.velocity, dt * this.speed)
      );
    }
  }
}

// 2. `entity` keyword - Component definition
export entity Player {
  position: vec3 = [0, 0, 0];
  velocity: vec3 = [0, 0, 0];
  health: number = 100;

  // Entity methods
  takeDamage(amount: number): void {
    this.health -= amount;
    if (this.health <= 0) {
      this.emit("death");
    }
  }
}

// 3. `world` keyword - Scene container
export world MainGame {
  systems: [MovementSystem, CombatSystem, UISystem];

  onLoad() {
    console.log("World loaded!");
  }
}

// 4. HoloScript-specific imports
import { loadWorld, query } from "@holoscript/core";
import { scene } from "./level.holo";  // Import .holo directly!
```

